import{_ as d,o as e,c as r,ag as o}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"附录 C：术语表","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/appendix-c-glossary.md","filePath":"chapters/appendix-c-glossary.md"}'),a={name:"chapters/appendix-c-glossary.md"};function c(n,t,i,h,s,C){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="附录-c-术语表" tabindex="-1">附录 C：术语表 <a class="header-anchor" href="#附录-c-术语表" aria-label="Permalink to &quot;附录 C：术语表&quot;">​</a></h1><p>本术语表收录了全书中频繁出现的中英文术语，按拼音首字母排序。每个术语标注了英文原文与简要说明，方便读者在阅读过程中随时查阅。</p><hr><table tabindex="0"><thead><tr><th>术语</th><th>English</th><th>说明</th></tr></thead><tbody><tr><td>BM25 全文索引</td><td>BM25 Full-Text Index</td><td>基于词频与逆文档频率的经典全文检索算法，本项目中作为混合检索的文本匹配分支。见 Ch5。</td></tr><tr><td>Cross-Encoder 重排序</td><td>Cross-Encoder Reranking</td><td>将 query 与 candidate 拼接后送入 Transformer 模型计算相关性分数的精排方法，精度高但开销大。见 Ch7。</td></tr><tr><td>半衰期</td><td>Half-Life</td><td>记忆衰减模型中的核心参数，表示记忆分数衰减到一半所需的时间（天数），由 <code>baseHalfLifeDays</code> 配置。见 Ch11。</td></tr><tr><td>边缘记忆</td><td>Peripheral Memory</td><td><code>MemoryTier</code> 中最低优先级的层级，衰减最快，长期不访问可能被自动清理。见 Ch11。</td></tr><tr><td>层级管理</td><td>Tier Management</td><td>将记忆按重要程度分为 core、working、peripheral 三个层级，控制衰减速率与检索优先级的机制。见 Ch11。</td></tr><tr><td>粗排</td><td>Candidate Retrieval</td><td>检索管线的第一阶段，从全量记忆中快速筛选出候选集合，由 <code>candidatePoolSize</code> 控制大小。见 Ch6。</td></tr><tr><td>分块</td><td>Chunking</td><td>将长文本切分为适合向量嵌入的小段的过程，影响检索粒度与召回质量。见 Ch4。</td></tr><tr><td>工作记忆</td><td>Working Memory</td><td><code>MemoryTier</code> 中的中间层级，表示当前活跃使用的记忆。见 Ch11。</td></tr><tr><td>工作区边界</td><td>Workspace Boundary</td><td>按项目目录或自定义标识符隔离记忆的机制，防止不同工作区的记忆交叉污染。见 Ch13。</td></tr><tr><td>核心记忆</td><td>Core Memory</td><td><code>MemoryTier</code> 中最高优先级的层级，衰减最慢，存放最重要的长期记忆。见 Ch11。</td></tr><tr><td>混合检索</td><td>Hybrid Retrieval</td><td>同时使用向量相似度搜索与 BM25 全文检索，通过加权融合提升召回率与精度的检索策略。见 Ch6。</td></tr><tr><td>记忆反思</td><td>Memory Reflection</td><td>在会话结束时由 LLM 对积累的记忆进行回顾、归纳与整合的机制。见 Ch12。</td></tr><tr><td>记忆分类</td><td>Memory Category</td><td>将记忆按语义分为 profile、preferences、entities、events、cases、patterns 六类的分类体系。见 Ch10、Ch14。</td></tr><tr><td>记忆关系</td><td>Memory Relation</td><td>记忆之间的语义关联（supports、contradicts、extends、related），用于构建记忆图谱。见 Ch14。</td></tr><tr><td>记忆衰减</td><td>Memory Decay</td><td>模拟人类遗忘曲线，随时间推移降低记忆分数的机制，由 <code>DecayConfig</code> 配置。见 Ch11。</td></tr><tr><td>精排</td><td>Reranking</td><td>检索管线的第二阶段，对粗排候选使用更精确的模型重新评分排序。见 Ch7。</td></tr><tr><td>噪声过滤</td><td>Noise Filtering</td><td>识别并过滤低质量、重复或无关的记忆候选，提升最终检索结果的信噪比。见 Ch8。</td></tr><tr><td>噪声原型</td><td>Noise Prototype</td><td>预定义的噪声模式模板，用于快速识别常见的低质量内容，如寒暄、确认等。见 Ch8。</td></tr><tr><td>强化因子</td><td>Reinforcement Factor</td><td>被频繁访问的记忆获得的分数提升系数，由 <code>reinforcementFactor</code> 配置。见 Ch9。</td></tr><tr><td>去重决策</td><td>Deduplication Decision</td><td>智能提取阶段判断新记忆与已有记忆关系的决策，包括 create、merge、skip 等七种类型。见 Ch10。</td></tr><tr><td>生命周期钩子</td><td>Lifecycle Hook</td><td>插件在 OpenClaw 框架中的初始化、激活、销毁等关键时机的回调函数。见 Ch15。</td></tr><tr><td>事实键</td><td>Fact Key</td><td>记忆元数据中的唯一事实标识符，用于快速判断两条记忆是否描述同一事实。见 Ch10。</td></tr><tr><td>时间衰减</td><td>Time Decay</td><td>基于记忆创建或最后访问时间的评分衰减机制，由 <code>timeDecayHalfLifeDays</code> 控制。见 Ch9。</td></tr><tr><td>数据迁移</td><td>Data Migration</td><td>在插件版本升级时将旧数据结构转换为新格式的过程，由 <code>migrate.ts</code> 和 <code>memory-upgrader.ts</code> 实现。见 Ch17。</td></tr><tr><td>向量嵌入</td><td>Vector Embedding</td><td>将文本转换为高维向量表示的过程，使语义相似的文本在向量空间中距离接近。见 Ch4。</td></tr><tr><td>向量权重</td><td>Vector Weight</td><td>混合检索中向量相似度分数的权重系数，默认 0.7，由 <code>vectorWeight</code> 配置。见 Ch6。</td></tr><tr><td>长度归一化</td><td>Length Normalization</td><td>对不同长度的文本块进行评分校准的机制，防止长文本在评分中获得不公平的优势，锚点由 <code>lengthNormAnchor</code> 设置。见 Ch9。</td></tr><tr><td>置信度</td><td>Confidence</td><td>记忆元数据中表示该条记忆可靠程度的数值（0-1），由 LLM 提取时评估。见 Ch10。</td></tr><tr><td>智能提取</td><td>Smart Extraction</td><td>由 LLM 驱动的记忆提取流程，能自动从对话中识别值得记忆的信息并结构化存储。见 Ch10。</td></tr><tr><td>自适应检索</td><td>Adaptive Retrieval</td><td>根据查询特征动态调整检索策略（如切换模式、调整阈值）的机制。见 Ch8。</td></tr><tr><td>作用域</td><td>Scope</td><td>记忆的隔离命名空间，不同作用域的记忆互不可见，由 <code>ScopeConfig</code> 配置。见 Ch13。</td></tr><tr><td>Agent 工具</td><td>Agent Tool</td><td>暴露给 AI Agent 调用的记忆操作接口，如存储记忆、检索记忆、删除记忆等。见 Ch16。</td></tr><tr><td>ANN 索引</td><td>Approximate Nearest Neighbor Index</td><td>近似最近邻索引，用于在高维向量空间中快速找到与查询向量最相似的记录。见 Ch3。</td></tr><tr><td>LanceDB</td><td>LanceDB</td><td>本项目使用的嵌入式列式向量数据库，支持向量搜索与结构化查询。见 Ch3。</td></tr><tr><td>OAuth 认证</td><td>OAuth Authentication</td><td>用于 LLM API 访问的授权协议，由 <code>llm-oauth.ts</code> 实现。见 Ch10。</td></tr><tr><td>OpenClaw</td><td>OpenClaw</td><td>本插件所集成的 AI Agent 框架，提供插件化架构与生命周期管理。见 Ch1、Ch15。</td></tr></tbody></table><hr><blockquote><p><strong>关于中英文混排的约定：</strong> 本书在行文中遵循&quot;中文与英文之间加空格&quot;的排版惯例，例如写作&quot;使用 LanceDB 存储&quot;而非&quot;使用LanceDB存储&quot;。术语表中的中文术语名也遵循此规则。</p></blockquote>',6)])])}const m=d(a,[["render",c]]);export{p as __pageData,m as default};
